/**
 * Analytics Preview CLI Command
 *
 * Shows what data would be submitted without actually submitting it
 *
 * Usage: npx strray-ai analytics preview [--type reflections|logs|metrics|patterns] [--all]
 */
import { program } from "commander";
import { ConsentManager } from "../../analytics/consent-manager.js";
export const analyticsPreviewCommand = program
    .command("analytics preview")
    .description("Preview what data would be submitted (without submitting)")
    .option("-t, --type <type>", "Specific data type to preview", "all")
    .option("--all", "Preview all data types", false)
    .action(async (options) => {
    console.log("👁️ 0xRay Central Analytics - Data Preview\n");
    try {
        const consentManager = new ConsentManager();
        const status = await consentManager.initialize();
        // Check if analytics is enabled
        if (!status.analyticsEnabled) {
            console.log("❌ Analytics is currently disabled.");
            console.log(`\n💡 Enable analytics first: npx strray-ai analytics enable`);
            console.log(`   Then preview what would be submitted: npx strray-ai analytics preview`);
            return;
        }
        console.log("🔍 This preview shows what anonymized data would be submitted.\n");
        // Show what gets anonymized vs preserved
        console.log("🔒 What Gets REMOVED (Privacy Protection):");
        console.log("  ❌ Project names and company information");
        console.log("  ❌ Repository URLs and file paths");
        console.log("  ❌ User names, emails, and personal identifiers");
        console.log("  ❌ IP addresses and precise timestamps");
        console.log("  ❌ API keys, secrets, and credentials");
        console.log("  ❌ Actual code snippets and proprietary logic");
        console.log("\n✅ What Gets PRESERVED (For Learning):");
        console.log("  ✅ Agent performance metrics (success rates, confidence scores)");
        console.log("  ✅ Complexity ratings and outcomes");
        console.log("  ✅ Pattern effectiveness data");
        console.log("  ✅ Anonymized emotional/struggle patterns");
        console.log("  ✅ Counterfactual analysis structures");
        // Show anonymization example
        console.log("\n📊 Anonymization Example:");
        console.log("  📥 Before (Local - Never Submitted):");
        console.log("    {");
        console.log(`      "project": "acme-corp/legacy-system",`);
        console.log(`      "reflection": "Fixed bug in user authentication...",`);
        console.log(`      "filePath": "/Users/john/projects/legacy/src/auth.ts",`);
        console.log(`      "author": "john.doe@acme.com",`);
        console.log(`      "code": "function authenticate(user) { ... }"`);
        console.log("    }");
        console.log("\n  📤 After (Anonymized - What Gets Submitted):");
        console.log("    {");
        console.log(`      "submissionId": "uuid-v4",`);
        console.log(`      "taskType": "bug_fix",`);
        console.log(`      "complexity": 75,`);
        console.log(`      "routedAgent": "bug-triage-specialist",`);
        console.log(`      "success": true,`);
        console.log(`      "emotionalContext": {`);
        console.log(`        "struggleLevel": "medium",`);
        console.log(`        "hasCounterfactualAnalysis": true,`);
        console.log(`        "depthScore": 4`);
        console.log("      },");
        console.log(`      "patterns": {`);
        console.log(`        "keywords": ["bug", "authentication", "critical"],`);
        console.log(`        "successRate": 0.85`);
        console.log("      }");
        console.log("    }");
        // Show enabled categories
        const categories = consentManager.getCategories();
        const enabledCategories = categories.filter(c => c.enabled);
        console.log("\n📂 Currently Enabled Categories:");
        enabledCategories.forEach(cat => {
            console.log(`  ✅ ${cat.name.padEnd(20)} ${cat.description}`);
        });
        const disabledCategories = categories.filter(c => !c.enabled);
        if (disabledCategories.length > 0) {
            console.log("\n❌ Disabled Categories (Will Not Be Submitted):");
            disabledCategories.forEach(cat => {
                console.log(`  ❌ ${cat.name.padEnd(20)} ${cat.description}`);
            });
        }
        // Show privacy guarantees
        console.log("\n🔐 Privacy Guarantees:");
        console.log("  ✅ Your data is anonymized before leaving your machine");
        console.log("  ✅ All submissions encrypted in transit (HTTPS/TLS)");
        console.log("  ✅ You can disable anytime: npx strray-ai analytics disable");
        console.log("  ✅ Request data deletion anytime");
        console.log("  ✅ Full transparency - see exactly what's submitted");
        console.log("\n💡 Next Steps:");
        console.log("  1. Review this preview carefully");
        console.log("  2. Enable specific categories: npx strray-ai analytics enable --categories reflections,metrics");
        console.log("  3. View current status: npx strray-ai analytics status");
        console.log("  4. Learn more: docs/architecture/central-analytics-store.md");
        console.log("\n📖 Documentation:");
        console.log("  • Architecture: docs/architecture/central-analytics-store.md");
        console.log("  • Privacy Policy: [To be published]");
        console.log("  • FAQ: docs/quickstart/central-analytics-quickstart.md");
    }
    catch (error) {
        console.error("❌ Failed to preview analytics:", error instanceof Error ? error.message : String(error));
        console.error("\n💡 Try: npx strray-ai analytics preview --help");
        process.exit(1);
    }
});
export default analyticsPreviewCommand;
